import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import api from '../../../lib/api';
import type { Expense } from '../types';
import { EXPENSE_CATEGORIES } from '../types';
import { formatCLP } from '../helpers';
import { Plus, Trash2, Download } from 'lucide-react';

interface Props {
  projectId: string;
}

const CATEGORY_ICONS: Record<string, string> = {
  material: '🧱',
  transport: '🚛',
  tools: '🔧',
  contingency: '⚠️',
};

export function ExpensesTab({ projectId }: Props) {
  const queryClient = useQueryClient();
  const [form, setForm] = useState<Omit<Expense, 'id'>>({
    category: 'material',
    description: '',
    amount: 0,
    date: new Date().toISOString().split('T')[0],
    document_url: '',
  });
  const [open, setOpen] = useState(false);

  const { data: expenses = [], isLoading } = useQuery<Expense[]>({
    queryKey: ['expenses', projectId],
    queryFn: async () => {
      if (!projectId) return [];
      const res = await api.get(`/expenses?project_id=${projectId}`);
      return res.data;
    },
    enabled: !!projectId,
  });

  const createMutation = useMutation({
    mutationFn: async (newExpense: Omit<Expense, 'id'>) => {
      const payload = {
        ...newExpense,
        project_id: projectId,
        expense_type: newExpense.category // mapped according to backend entity
      };
      const res = await api.post('/expenses', payload);
      return res.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['expenses', projectId] });
      queryClient.invalidateQueries({ queryKey: ['expenses-summary', projectId] });
      setForm({ category: 'material', description: '', amount: 0, date: new Date().toISOString().split('T')[0], document_url: '' });
      setOpen(false);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await api.delete(`/expenses/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['expenses', projectId] });
      queryClient.invalidateQueries({ queryKey: ['expenses-summary', projectId] });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.description || form.amount <= 0 || !projectId) return;
    createMutation.mutate(form);
  };

  const totalExpenses = expenses.reduce((s, e: Expense) => s + Number(e.amount), 0);

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <div>
          <h3 className="text-white font-bold">Gastos del Proyecto</h3>
          <p className="text-gray-400 text-sm">Total: <span className="text-white font-bold">{formatCLP(totalExpenses)}</span></p>
        </div>
        <button
          onClick={() => setOpen(true)}
          disabled={!projectId}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white text-sm font-medium px-4 py-2 rounded-xl transition-colors"
        >
          <Plus size={14} /> Registrar gasto
        </button>
      </div>

      {/* Form modal */}
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setOpen(false)} />
          <form
            onSubmit={handleSubmit}
            className="relative bg-gray-900 border border-white/10 rounded-2xl w-full max-w-md p-6 shadow-2xl z-10 space-y-4"
          >
            <h3 className="text-white font-bold text-lg">Nuevo Gasto</h3>

            <div>
              <label className="text-xs text-gray-400 mb-1 block">Categoría</label>
              <select
                value={form.category}
                onChange={(e) => setForm({ ...form, category: e.target.value as Expense['category'] })}
                className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500"
              >
                {EXPENSE_CATEGORIES.map((c) => (
                  <option key={c.value} value={c.value}>{CATEGORY_ICONS[c.value]} {c.label}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="text-xs text-gray-400 mb-1 block">Descripción</label>
              <input
                value={form.description}
                onChange={(e) => setForm({ ...form, description: e.target.value })}
                placeholder="Ej: Cemento 20 sacos"
                required
                className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500"
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-xs text-gray-400 mb-1 block">Monto ($)</label>
                <input
                  type="number"
                  value={form.amount || ''}
                  onChange={(e) => setForm({ ...form, amount: parseFloat(e.target.value) || 0 })}
                  placeholder="0"
                  required
                  min={1}
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500"
                />
              </div>
              <div>
                <label className="text-xs text-gray-400 mb-1 block">Fecha</label>
                <input
                  type="date"
                  value={form.date}
                  onChange={(e) => setForm({ ...form, date: e.target.value })}
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500"
                />
              </div>
            </div>

            <div>
              <label className="text-xs text-gray-400 mb-1 block">URL de Comprobante / Factura (Opcional)</label>
              <input
                value={form.document_url || ''}
                onChange={(e) => setForm({ ...form, document_url: e.target.value })}
                placeholder="https://enlace-a-la-foto.com/..."
                className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500"
              />
            </div>

            <div className="flex gap-3 pt-2">
              <button type="button" onClick={() => setOpen(false)} className="flex-1 py-2 rounded-xl border border-white/10 text-gray-400 text-sm hover:bg-white/5 transition-colors">
                Cancelar
              </button>
              <button disabled={createMutation.isPending} type="submit" className="flex-1 py-2 rounded-xl bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium transition-colors disabled:opacity-50">
                {createMutation.isPending ? 'Registrando...' : 'Registrar'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Expenses list */}
      {isLoading ? (
        <div className="text-center py-16 text-gray-400">
          <p>Cargando gastos...</p>
        </div>
      ) : expenses.length === 0 ? (
        <div className="text-center py-16 text-gray-600">
          <p className="text-4xl mb-3">📋</p>
          <p>Sin gastos registrados</p>
        </div>
      ) : (
        <div className="space-y-2">
          {expenses.map((e) => (
            <div key={e.id} className="flex items-center gap-3 p-3 bg-gray-800/50 rounded-xl border border-white/5 group">
              <span className="text-2xl">{CATEGORY_ICONS[e.category || e.expense_type as any] || '📋'}</span>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <p className="text-white text-sm font-medium">{e.description}</p>
                  {e.document_url && (
                    <a 
                      href={e.document_url} 
                      target="_blank" 
                      rel="noreferrer"
                      className="text-[10px] text-blue-400 hover:underline flex items-center gap-1"
                    >
                      <Download size={10} /> Factura
                    </a>
                  )}
                </div>
                <p className="text-gray-500 text-xs">{EXPENSE_CATEGORIES.find((c) => c.value === (e.category || e.expense_type))?.label || 'Gasto'} · {e.date}</p>
              </div>
              <span className="text-white font-bold tabular-nums">{formatCLP(e.amount)}</span>
              <button
                onClick={() => deleteMutation.mutate(e.id)}
                disabled={deleteMutation.isPending}
                className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 transition-all disabled:opacity-50"
              >
                <Trash2 size={13} />
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import type { Worker } from '../types';
import { formatCLP } from '../helpers';
import { Plus, Trash2 } from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import api from '../../../lib/api';

interface Props {
  projectId: string;
}

export function WorkersTab({ projectId }: Props) {
  const queryClient = useQueryClient();
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState<Omit<Worker, 'id' | 'totalPaid'>>({
    name: '',
    specialty: '',
    dailyRate: 0,
    daysWorked: 0,
  });

  const { data: assignments = [], isLoading } = useQuery({
    queryKey: ['worker-assignments', projectId],
    queryFn: async () => {
      const response = await api.get('/worker-assignments', {
        params: { project_id: projectId }
      });
      return response.data;
    },
    enabled: !!projectId,
  });

  const addMutation = useMutation({
    mutationFn: async (workerData: Omit<Worker, 'id' | 'totalPaid'>) => {
      // 1. Create Worker
      const wRes = await api.post('/workers', {
        name: workerData.name,
        role: workerData.specialty,
        daily_rate: workerData.dailyRate,
      });
      const worker = wRes.data;

      // 2. Assign to Project
      const totalPaid = workerData.dailyRate * workerData.daysWorked;
      const aRes = await api.post('/worker-assignments', {
        worker_id: worker.id,
        project_id: projectId,
        daily_rate: workerData.dailyRate,
        total_paid: totalPaid,
        start_date: new Date().toISOString().split('T')[0],
      });
      return aRes.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['worker-assignments', projectId] });
      queryClient.invalidateQueries({ queryKey: ['workers-summary', projectId] });
      queryClient.invalidateQueries({ queryKey: ['budget', projectId] });
      setForm({ name: '', specialty: '', dailyRate: 0, daysWorked: 0 });
      setOpen(false);
    }
  });

  const deleteMutation = useMutation({
    mutationFn: async (assignmentId: string) => {
      await api.delete(`/worker-assignments/${assignmentId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['worker-assignments', projectId] });
      queryClient.invalidateQueries({ queryKey: ['workers-summary', projectId] });
      queryClient.invalidateQueries({ queryKey: ['budget', projectId] });
    }
  });

  const submit = (e: React.FormEvent) => {
    e.preventDefault();
    addMutation.mutate(form);
  };

  const total = assignments.reduce((s: number, a: any) => s + Number(a.total_paid), 0);

  if (isLoading) {
    return <div className="text-center py-8 text-gray-500">Cargando trabajadores...</div>;
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <div>
          <h3 className="text-white font-bold">Trabajadores</h3>
          <p className="text-gray-400 text-sm">Total pagado: <span className="text-white font-bold">{formatCLP(total)}</span></p>
        </div>
        <button
          onClick={() => setOpen(true)}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium px-4 py-2 rounded-xl transition-colors"
        >
          <Plus size={14} /> Añadir trabajador
        </button>
      </div>

      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setOpen(false)} />
          <form onSubmit={submit} className="relative bg-gray-900 border border-white/10 rounded-2xl w-full max-w-md p-6 shadow-2xl z-10 space-y-4">
            <h3 className="text-white font-bold text-lg">Nuevo Trabajador</h3>
            <div className="grid grid-cols-2 gap-3">
              <div className="col-span-2">
                <label className="text-xs text-gray-400 mb-1 block">Nombre</label>
                <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500" />
              </div>
              <div className="col-span-2">
                <label className="text-xs text-gray-400 mb-1 block">Especialidad</label>
                <input value={form.specialty} onChange={(e) => setForm({ ...form, specialty: e.target.value })}
                  placeholder="Gasfiter, Electricista…"
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500" />
              </div>
              <div>
                <label className="text-xs text-gray-400 mb-1 block">Jornal diario ($)</label>
                <input type="number" min={0} value={form.dailyRate || ''} onChange={(e) => setForm({ ...form, dailyRate: parseFloat(e.target.value) || 0 })}
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500" />
              </div>
              <div>
                <label className="text-xs text-gray-400 mb-1 block">Días trabajados</label>
                <input type="number" min={0} value={form.daysWorked || ''} onChange={(e) => setForm({ ...form, daysWorked: parseFloat(e.target.value) || 0 })}
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500" />
              </div>
            </div>
            <div className="bg-gray-800/60 rounded-xl p-3 text-center">
              <p className="text-xs text-gray-400 mb-0.5">Total a pagar</p>
              <p className="text-white font-black text-xl">{formatCLP(form.dailyRate * form.daysWorked)}</p>
            </div>
            <div className="flex gap-3">
              <button type="button" onClick={() => setOpen(false)} className="flex-1 py-2 rounded-xl border border-white/10 text-gray-400 text-sm hover:bg-white/5 transition-colors" disabled={addMutation.isPending}>Cancelar</button>
              <button type="submit" className="flex-1 py-2 rounded-xl bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium transition-colors" disabled={addMutation.isPending}>{addMutation.isPending ? 'Guardando...' : 'Guardar'}</button>
            </div>
          </form>
        </div>
      )}

      {assignments.length === 0 ? (
        <div className="text-center py-16 text-gray-600"><p className="text-4xl mb-3">👷</p><p>Sin trabajadores registrados</p></div>
      ) : (
        <div className="space-y-2">
          {assignments.map((a: any) => {
            const daysCalc = Number(a.daily_rate) > 0 ? Number(a.total_paid)/Number(a.daily_rate) : 0;
            return (
              <div key={a.id} className="flex items-center gap-3 p-3 bg-gray-800/50 rounded-xl border border-white/5 group">
                <div className="w-9 h-9 rounded-full bg-blue-500/20 border border-blue-500/30 flex items-center justify-center text-sm font-bold text-blue-300 shrink-0">
                  {a.worker?.name?.charAt(0).toUpperCase() || '?'}
                </div>
                <div className="flex-1">
                  <p className="text-white text-sm font-medium">{a.worker?.name}</p>
                  <p className="text-gray-500 text-xs">{a.worker?.role} · {daysCalc.toFixed(1)} días × {formatCLP(Number(a.daily_rate))}</p>
                </div>
                <span className="text-white font-bold tabular-nums">{formatCLP(Number(a.total_paid))}</span>
                <button disabled={deleteMutation.isPending} onClick={() => deleteMutation.mutate(a.id)} className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 transition-all disabled:opacity-50">
                  <Trash2 size={13} />
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import type { Budget, FinancialSummary, Stage, LineItem } from './types';
import { nanoid } from './utils';

// ─── Financial computations ────────────────────────────────────────────────

export function calcLineItem(item: Omit<LineItem, 'total'>): LineItem {
  return { ...item, total: item.quantity * item.unitPrice };
}

export function calcStageTotal(stage: Stage): number {
  return stage.items.reduce((sum, i) => sum + i.total, 0);
}

export function calcFinancials(
  budget: Budget,
  apiRealExpenses: number = 0,
  apiWorkerPayments: number = 0
): FinancialSummary {
  const estimatedCost = budget.stages.reduce(
    (s, stage) => s + calcStageTotal(stage),
    0
  );

  // Use API values if provided, fallback to legacy local arrays if API values are not provided or arrays exist
  const realExpenses = apiRealExpenses || (budget.expenses?.reduce((s, e) => s + e.amount, 0) || 0);
  const workerPayments = apiWorkerPayments || (budget.workers?.reduce((s, w) => s + (w as any).totalPaid, 0) || 0);

  const totalRealCost = realExpenses + workerPayments;
  const projectedProfit = budget.clientPrice - estimatedCost;
  const currentProfit = budget.clientPrice - totalRealCost;
  const margin =
    budget.clientPrice > 0
      ? Math.round((projectedProfit / budget.clientPrice) * 100)
      : 0;

  const executedValue = budget.stages.reduce(
    (s, stage) => s + stage.items.reduce((sum, i) => sum + ((i.quantityExecuted || 0) * i.unitPrice), 0),
    0
  );

  return {
    estimatedCost,
    realExpenses,
    workerPayments,
    totalRealCost,
    projectedProfit,
    currentProfit,
    margin,
    executedValue,
  };
}

// ─── Formatters ────────────────────────────────────────────────────────────

export function formatCLP(value: number): string {
  return new Intl.NumberFormat('es-CL', {
    style: 'currency',
    currency: 'CLP',
    maximumFractionDigits: 0,
  }).format(value);
}

// ─── Stage / item helpers ─────────────────────────────────────────────────

export function newStage(name: string): Stage {
  return { id: nanoid(), name, progress: 0, items: [] };
}

export function newLineItem(): LineItem {
  return {
    id: nanoid(),
    name: '',
    quantity: 1,
    unit: 'm2',
    unitPrice: 0,
    costCode: '',
    total: 0,
  };
}

export interface LineItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  unitPrice: number;
  costCode?: string;
  total: number; // computed: quantity * unitPrice
  // APU & cubicacion
  apuTemplateId?: string;
  cubicationMode?: 'manual' | 'dimensions' | 'cad' | 'pdf';
  dimLength?: number;
  dimWidth?: number;
  dimHeight?: number;
  dimThickness?: number;
  formula?: string;
  geometryData?: any;
  // Ejecución real
  quantityExecuted?: number;
  realCost?: number;
}

export interface Stage {
  id: string;
  name: string;
  progress: number; // 0–100
  items: LineItem[];
}

export interface Expense {
  id: string;
  category: 'material' | 'transport' | 'tools' | 'contingency';
  expense_type?: string;
  description: string;
  amount: number;
  date: string;
  document_url?: string;
}

export interface Worker {
  id: string;
  name: string;
  specialty: string;
  dailyRate: number;
  daysWorked: number;
  totalPaid: number;
  phone?: string;
  performance?: number; // 1-5
  notes?: string;
}

export interface Budget {
  id: string;
  projectName: string;
  clientName: string;
  status: 'draft' | 'editing' | 'sent' | 'approved';
  clientPrice: number;
  stages: Stage[];
  expenses: Expense[];
  workers: Worker[];
}

// Derived financials (computed from Budget)
export interface FinancialSummary {
  estimatedCost: number;
  realExpenses: number;
  workerPayments: number;
  totalRealCost: number;
  projectedProfit: number;
  currentProfit: number;
  margin: number; // percentage
  executedValue: number; // Sum of (quantityExecuted * unitPrice)
}

